diffs.replacement:
{
  "name": "SmartInfoQueue",
  "description": "Convert idle waiting time at public service places into an engaging, educational experience with AI-generated quizzes and location-based insights.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

export interface LocationData {
  lat: number;
  lon: number;
  displayName: string;
  type?: string;
  name?: string;
}

export interface QuizQuestion {
  question: string;
  options: string[];
  answer: string;
  explanation: string;
  type: 'multiple-choice' | 'true-false';
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  isThinking?: boolean;
}

export enum AppScreen {
  HOME = 'HOME',
  QUIZ = 'QUIZ',
  INFO = 'INFO',
  CHAT = 'CHAT',
  MAP = 'MAP'
}

import { GoogleGenAI, Type } from "@google/genai";
import { QuizQuestion } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getPlaceInfo = async (placeName: string, placeType: string): Promise<string> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Provide a brief, interesting, and visitor-friendly summary about "${placeName}" (Type: ${placeType}). Include 3-4 interesting facts or helpful tips for someone waiting here. Keep it under 150 words. Use friendly markdown.`,
    config: {
      temperature: 0.7,
    }
  });
  return response.text || "No information available for this location.";
};

export const generateQuiz = async (placeName: string, placeType: string): Promise<QuizQuestion[]> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Generate a fun 5-question quiz for visitors waiting at "${placeName}" (${placeType}). Mix multiple-choice and true/false questions. Make them educational but lighthearted.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            options: { type: Type.ARRAY, items: { type: Type.STRING } },
            answer: { type: Type.STRING },
            explanation: { type: Type.STRING },
            type: { type: Type.STRING, description: 'either multiple-choice or true-false' }
          },
          required: ["question", "options", "answer", "explanation", "type"]
        }
      }
    }
  });

  try {
    return JSON.parse(response.text || "[]");
  } catch (e) {
    console.error("Failed to parse quiz JSON", e);
    return [];
  }
};

export const chatWithAI = async (
  message: string, 
  context: string, 
  history: { role: 'user' | 'model', text: string }[],
  useDeepThinking: boolean = false
): Promise<string> => {
  const ai = getAI();
  const model = useDeepThinking ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

  const config: any = {
    systemInstruction: `You are the SmartInfoQueue assistant. You help people waiting at "${context}". Be friendly, helpful, and concise.`,
  };

  if (useDeepThinking) {
    config.thinkingConfig = { thinkingBudget: 32768 };
  }

  const chat = ai.chats.create({
    model,
    config
  });

  // Simple history-less implementation for MVP demo, or we can map history
  // For this implementation, we send the prompt with context
  const response = await ai.models.generateContent({
    model,
    contents: `Context: Visitor is at ${context}. User asks: ${message}`,
    config
  });

  return response.text || "I'm sorry, I couldn't process that request.";
};

import React from 'react';
