export default Layout;

import React, { useState } from 'react';
import { QuizQuestion } from '../types';

interface QuizModuleProps {
  questions: QuizQuestion[];
  locationName: string;
}

const QuizModule: React.FC<QuizModuleProps> = ({ questions, locationName }) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const [score, setScore] = useState(0);
  const [showResult, setShowResult] = useState(false);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [isAnswered, setIsAnswered] = useState(false);

  if (!questions || questions.length === 0) {
    return (
      <div className="p-8 text-center">
        <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4">
          <i className="fa-solid fa-hourglass-start text-slate-400 text-2xl"></i>
        </div>
        <h3 className="text-slate-600 font-medium">Preparing your custom quiz...</h3>
      </div>
    );
  }

  const currentQuestion = questions[currentIdx];

  const handleAnswer = (option: string) => {
    if (isAnswered) return;
    setSelectedOption(option);
    setIsAnswered(true);
    if (option.toLowerCase() === currentQuestion.answer.toLowerCase()) {
      setScore(s => s + 1);
    }
  };

  const nextQuestion = () => {
    if (currentIdx + 1 < questions.length) {
      setCurrentIdx(currentIdx + 1);
      setSelectedOption(null);
      setIsAnswered(false);
    } else {
      setShowResult(true);
    }
  };

  const restartQuiz = () => {
    setCurrentIdx(0);
    setScore(0);
    setShowResult(false);
    setSelectedOption(null);
    setIsAnswered(false);
  };

  if (showResult) {
    return (
      <div className="p-6 text-center animate-in fade-in duration-500">
        <div className="mb-6 relative inline-block">
          <div className="w-32 h-32 rounded-full border-8 border-indigo-100 flex items-center justify-center mx-auto">
            <span className="text-4xl font-black text-indigo-600">{Math.round((score / questions.length) * 100)}%</span>
          </div>
          <i className="fa-solid fa-trophy text-yellow-500 text-4xl absolute -top-2 -right-2 transform rotate-12"></i>
        </div>
        <h2 className="text-2xl font-bold text-slate-800 mb-2">Quiz Completed!</h2>
        <p className="text-slate-500 mb-8">You scored {score} out of {questions.length} questions about {locationName}.</p>
        <button
          onClick={restartQuiz}
          className="w-full py-4 bg-indigo-600 text-white rounded-xl font-bold shadow-lg shadow-indigo-200 active:scale-95 transition-transform"
        >
          Try Again
        </button>
      </div>
    );
  }

  return (
    <div className="p-6 animate-in slide-in-from-right duration-300">
      <div className="flex justify-between items-center mb-6">
        <span className="text-xs font-bold text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full uppercase tracking-wider">
          Question {currentIdx + 1} / {questions.length}
        </span>
        <div className="flex gap-1">
          {questions.map((_, i) => (
            <div key={i} className={`w-2 h-2 rounded-full ${i <= currentIdx ? 'bg-indigo-600' : 'bg-slate-200'}`}></div>
          ))}
        </div>
      </div>

      <h3 className="text-xl font-bold text-slate-800 mb-8 leading-tight">
        {currentQuestion.question}
      </h3>

      <div className="space-y-3 mb-8">
        {currentQuestion.options.map((option, i) => {
          const isSelected = selectedOption === option;
          const isCorrect = option.toLowerCase() === currentQuestion.answer.toLowerCase();

          let cardStyle = "bg-white border-2 border-slate-100 text-slate-700";
          if (isAnswered) {
            if (isCorrect) cardStyle = "bg-emerald-50 border-emerald-500 text-emerald-700";
            else if (isSelected) cardStyle = "bg-rose-50 border-rose-500 text-rose-700";
          } else if (isSelected) {
            cardStyle = "bg-indigo-50 border-indigo-500 text-indigo-700";
          }

          return (
            <button
              key={i}
              disabled={isAnswered}
              onClick={() => handleAnswer(option)}
              className={`w-full p-4 rounded-xl text-left font-medium transition-all ${cardStyle} active:scale-98 shadow-sm`}
            >
              <div className="flex items-center justify-between">
                <span>{option}</span>
                {isAnswered && isCorrect && <i className="fa-solid fa-circle-check text-emerald-500"></i>}
                {isAnswered && !isCorrect && isSelected && <i className="fa-solid fa-circle-xmark text-rose-500"></i>}
              </div>
            </button>
          );
        })}
      </div>

      {isAnswered && (
        <div className="bg-slate-50 p-4 rounded-xl mb-6 animate-in fade-in slide-in-from-top-2">
          <p className="text-sm text-slate-600 italic">
            <span className="font-bold text-slate-700 not-italic">Did you know? </span>
            {currentQuestion.explanation}
          </p>
        </div>
      )}

      <button
        disabled={!isAnswered}
        onClick={nextQuestion}
        className={`w-full py-4 rounded-xl font-bold shadow-lg transition-all ${
          isAnswered ? 'bg-indigo-600 text-white shadow-indigo-200' : 'bg-slate-200 text-slate-400 shadow-none'
        }`}
      >
        {currentIdx + 1 === questions.length ? 'Finish Quiz' : 'Next Question'}
      </button>
    </div>
  );
};

export default QuizModule;

import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import QuizModule from './components/QuizModule';
import { LocationData, QuizQuestion, ChatMessage, AppScreen } from './types';
import { getPlaceInfo, generateQuiz, chatWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [activeScreen, setActiveScreen] = useState<AppScreen>(AppScreen.HOME);
  const [location, setLocation] = useState<LocationData | null>(null);
  const [info, setInfo] = useState<string>('');
  const [quiz, setQuiz] = useState<QuizQuestion[]>([]);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [chatInput, setChatInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isDeepThinking, setIsDeepThinking] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  // Auto-detect location on mount
  useEffect(() => {
    detectLocation();
    // Load cache from localStorage if available
    const cachedLoc = localStorage.getItem('s_location');
    const cachedInfo = localStorage.getItem('s_info');
    const cachedQuiz = localStorage.getItem('s_quiz');
    if (cachedLoc) setLocation(JSON.parse(cachedLoc));
    if (cachedInfo) setInfo(cachedInfo);
    if (cachedQuiz) setQuiz(JSON.parse(cachedQuiz));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const reverseGeocode = async (lat: number, lon: number) => {
    try {
      const res = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lon}`);
      const data = await res.json();
      const newLoc: LocationData = {
        lat,
        lon,
        displayName: data.display_name,
        type: data.type || data.category || 'Public Place',
        name: data.name || data.address.bank || data.address.hospital || data.address.university || data.address.amenity || 'Current Location'
      };
      updateLocationState(newLoc);
    } catch (e) {
      console.error("Geocoding failed", e);
    }
  };

  const detectLocation = () => {
    setIsLoading(true);
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          reverseGeocode(pos.coords.latitude, pos.coords.longitude);
        },
        (err) => {
          console.error(err);
          setIsLoading(false);
        }
      );
    }
  };

  const searchLocation = async (q: string) => {
    if (!q) return;
    setIsLoading(true);
    try {
      const res = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(q)}&limit=1`);
      const data = await res.json();
      if (data && data[0]) {
        const item = data[0];
        const newLoc: LocationData = {
          lat: parseFloat(item.lat),
          lon: parseFloat(item.lon),
          displayName: item.display_name,
          type: item.type || 'Location',
          name: item.display_name.split(',')[0]
        };
        updateLocationState(newLoc);
      }
    } catch (e) {
      console.error("Search failed", e);
    } finally {
      setIsLoading(false);
    }
  };

  const updateLocationState = async (loc: LocationData) => {
    setLocation(loc);
    localStorage.setItem('s_location', JSON.stringify(loc));

    // Fetch AI content
    setIsLoading(true);
    try {
      const [newInfo, newQuiz] = await Promise.all([
        getPlaceInfo(loc.name || loc.displayName, loc.type || ''),
        generateQuiz(loc.name || loc.displayName, loc.type || '')
      ]);
      setInfo(newInfo);
      setQuiz(newQuiz);
      localStorage.setItem('s_info', newInfo);
      localStorage.setItem('s_quiz', JSON.stringify(newQuiz));
    } catch (e) {
      console.error("AI fetch failed", e);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSendMessage = async () => {
    if (!chatInput.trim()) return;
    const userMsg: ChatMessage = { role: 'user', text: chatInput };
    setChatHistory(prev => [...prev, userMsg]);
    setChatInput('');

    const botThinking: ChatMessage = { role: 'model', text: 'Thinking...', isThinking: true };
    setChatHistory(prev => [...prev, botThinking]);

    try {
      const context = location ? `${location.name} (${location.type})` : "Public area";
      const responseText = await chatWithAI(chatInput, context, chatHistory.map(m => ({ role: m.role, text: m.text })), isDeepThinking);
      setChatHistory(prev => {
        const next = [...prev];
        next.pop(); // remove thinking
        return [...next, { role: 'model', text: responseText }];
      });
    } catch (e) {
      setChatHistory(prev => {
        const next = [...prev];
        next.pop();
        return [...next, { role: 'model', text: "Sorry, I had trouble connecting to the AI brain." }];
      });
    }
  };

  const renderHome = () => (
    <div className="p-6 space-y-6">
      <section className="bg-indigo-50 rounded-2xl p-6 border border-indigo-100">
        <div className="flex items-center gap-4 mb-4">
          <div className="w-12 h-12 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg">
            <i className="fa-solid fa-location-dot text-xl"></i>
          </div>
          <div>
            <h2 className="text-sm font-semibold text-indigo-900/60 uppercase tracking-widest">You are at</h2>
            <h3 className="text-xl font-bold text-indigo-900 truncate max-w-[200px]">{location?.name || 'Detecting...'}</h3>
          </div>
        </div>
        <div className="relative mb-4">
          <input 
            type="text"
            placeholder="Search for a place..."
            className="w-full bg-white border border-slate-200 rounded-xl py-3 px-4 pr-12 focus:outline-none focus:ring-2 focus:ring-indigo-500 text-sm shadow-sm"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && searchLocation(searchQuery)}
          />
          <button 
            onClick={() => searchLocation(searchQuery)}
            className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-indigo-600"
          >
            <i className="fa-solid fa-magnifying-glass"></i>
          </button>
        </div>
        <button 
          onClick={detectLocation}
          className="flex items-center gap-2 text-indigo-600 text-xs font-bold uppercase tracking-wider"
        >
          <i className="fa-solid fa-crosshairs"></i>
          Detect Current Location
        </button>
      </section>

      <div className="grid grid-cols-2 gap-4">
        <button 
          onClick={() => setActiveScreen(AppScreen.INFO)}
          className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm text-left active:scale-95 transition-transform"
        >
          <div className="w-10 h-10 bg-amber-100 rounded-lg flex items-center justify-center text-amber-600 mb-3">
            <i className="fa-solid fa-book-open"></i>
          </div>
          <h4 className="font-bold text-slate-800 text-sm">Place Info</h4>
          <p className="text-[10px] text-slate-400 mt-1 uppercase font-semibold">Learn & explore</p>
        </button>

        <button 
          onClick={() => setActiveScreen(AppScreen.QUIZ)}
          className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm text-left active:scale-95 transition-transform"
        >
          <div className="w-10 h-10 bg-emerald-100 rounded-lg flex items-center justify-center text-emerald-600 mb-3">
            <i className="fa-solid fa-gamepad"></i>
          </div>
          <h4 className="font-bold text-slate-800 text-sm">Play Quiz</h4>
          <p className="text-[10px] text-slate-400 mt-1 uppercase font-semibold">Challenge yourself</p>
        </button>
      </div>

      <section className="bg-gradient-to-br from-indigo-600 to-violet-700 rounded-2xl p-6 text-white shadow-xl">
        <h3 className="font-bold text-lg mb-2">Feeling bored?</h3>
        <p className="text-indigo-100 text-sm mb-6">Our AI is ready to chat and answer any questions about where you are!</p>
        <button 
          onClick={() => setActiveScreen(AppScreen.CHAT)}
          className="w-full py-3 bg-white text-indigo-600 rounded-xl font-bold flex items-center justify-center gap-2 active:scale-95 transition-transform"
        >
          <i className="fa-solid fa-comment-dots"></i>
          Start Chatting
        </button>
      </section>

      {isLoading && (
        <div className="fixed inset-0 bg-white/60 backdrop-blur-sm z-50 flex flex-col items-center justify-center">
          <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mb-4"></div>
          <p className="text-indigo-600 font-bold animate-pulse">Syncing with AI...</p>
        </div>
      )}
    </div>
  );

  const renderInfo = () => (
    <div className="p-6">
      <button 
        onClick={() => setActiveScreen(AppScreen.HOME)}
        className="mb-4 text-slate-400 flex items-center gap-2 text-sm"
      >
        <i className="fa-solid fa-arrow-left"></i> Back
      </button>
      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <img src={`https://picsum.photos/seed/${location?.name || 'place'}/400/200`} alt="Location" className="w-full h-40 object-cover" />
        <div className="p-6">
          <h2 className="text-2xl font-bold text-slate-800 mb-4">{location?.name || 'Local Guide'}</h2>
          <div className="prose prose-slate max-w-none text-slate-600 text-sm leading-relaxed space-y-4">
            {info.split('\n').map((line, i) => <p key={i}>{line}</p>)}
          </div>
        </div>
      </div>
    </div>
  );

  const renderChat = () => (
    <div className="flex flex-col h-full bg-slate-50">
      <div className="p-4 bg-white border-b border-slate-200 flex items-center justify-between">
         <button onClick={() => setActiveScreen(AppScreen.HOME)} className="text-slate-400">
           <i className="fa-solid fa-arrow-left"></i>
         </button>
         <div className="text-center">
           <h3 className="font-bold text-slate-800">Smart Assistant</h3>
           <p className="text-[10px] text-emerald-500 font-bold uppercase tracking-wider">Online</p>
         </div>
         <div className="w-6"></div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scroll">
        {chatHistory.length === 0 && (
          <div className="text-center py-10 px-6">
            <div className="w-16 h-16 bg-indigo-100 rounded-full flex items-center justify-center mx-auto mb-4 text-indigo-600">
              <i className="fa-solid fa-robot text-2xl"></i>
            </div>
            <h4 className="font-bold text-slate-800">Hi there!</h4>
            <p className="text-slate-500 text-sm">Ask me anything about this place, its history, or what you can do while waiting.</p>
          </div>
        )}
        {chatHistory.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-3 rounded-2xl shadow-sm ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-white text-slate-700 rounded-tl-none border border-slate-100'
            }`}>
              {msg.isThinking && <i className="fa-solid fa-spinner animate-spin mr-2"></i>}
              <p className="text-sm">{msg.text}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="p-4 bg-white border-t border-slate-200">
        <div className="flex items-center gap-3 mb-3">
          <label className="flex items-center gap-2 cursor-pointer group">
            <div className={`w-8 h-4 rounded-full p-0.5 transition-colors ${isDeepThinking ? 'bg-indigo-600' : 'bg-slate-200'}`}>
               <input type="checkbox" className="hidden" checked={isDeepThinking} onChange={() => setIsDeepThinking(!isDeepThinking)} />
               <div className={`w-3 h-3 bg-white rounded-full transition-transform ${isDeepThinking ? 'translate-x-4' : 'translate-x-0'}`}></div>
            </div>
            <span className="text-[10px] font-bold uppercase tracking-wider text-slate-400 group-hover:text-indigo-600">Deep Thinking</span>
          </label>
        </div>
        <div className="flex gap-2">
          <input 
            type="text"
            className="flex-1 bg-slate-100 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
            placeholder="Type your question..."
            value={chatInput}
            onChange={(e) => setChatInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
          />
          <button 
            onClick={handleSendMessage}
            className="w-12 h-12 bg-indigo-600 rounded-xl text-white flex items-center justify-center shadow-lg active:scale-95"
          >
            <i className="fa-solid fa-paper-plane"></i>
          </button>
        </div>
      </div>
    </div>
  );

  return (
    <Layout 
      activeScreen={activeScreen} 
      onNavigate={setActiveScreen} 
      title="SmartInfoQueue"
    >
      {activeScreen === AppScreen.HOME && renderHome()}
      {activeScreen === AppScreen.INFO && renderInfo()}
      {activeScreen === AppScreen.QUIZ && (
        <div className="h-full">
           <button 
