      )}

      {showMap && (
        <MapPicker 
          initialLocation={location} 
          onLocationSelect={(lat, lon) => reverseGeocode(lat, lon)}
          onClose={() => setShowMap(false)}
        />
      )}
    </Layout>
  );
};

